                self.is_valid(),
            ensures
                l as nat == self.view().len(),
        {
            self.data.len()
        }

        pub fn new() -> (s: Self)
            ensures
                s.is_valid(),
                s.view().len() == 0,
        {
            VerifiableQueue { data: Vec::new() }
        }

